import http from '../http'
//实验室与设备接口


//设备

// 设备列表
export function DeviceListAll(query: any) {
    return http.get('/jkyErp/testInstrument/getList', query)
}

// 设备列表
export function DeviceList(query: any) {
    return http.get('/jkyErp/testInstrument/list', query)
}

// 设备信息列表详细
export function getDevice(id: any) {
    return http.get('/jkyErp/testInstrument/' + id)
}
// 新增设备
export function addDevice(data: any) {
    return http.post('/jkyErp/testInstrument/add', data)
}

// 修改设备
export function editDevice(data: any) {
    return http.post('/jkyErp/testInstrument/edit', data)
}

// 删除设备
export function delDevice(teamId: number) {
    return http.post('/jkyErp/testInstrument/del',teamId)
}




