<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="12" :sm="24">
              <a-form-item
                label="实验室名称："
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入实验室名称"
                  v-model:value="queryParams.name"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
        <template #picture="{ text }"
          ><img :src="text" alt="" style="whild: 50px; height: 50px"
        /></template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>
  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="实验室名称" name="name">
            <a-input placeholder="请输入实验室名称" v-model:value="form.name" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="联系电话" name="phone">
            <a-input placeholder="请输入联系电话" v-model:value="form.phone" />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="实验室编号">
            <a-input placeholder="请输入实验室编号" v-model:value="form.code" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="实验室管理员" :rules="[{ required: true }]">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.administintor"
              placeholder="请选实验室管理员"
            >
              <a-select-option
                v-for="item in selUserList"
                :key="item.name"
                :lable="item.name"
                :value="item.name"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="实验室地址" name="remark">
            <a-textarea
              rows="4"
              placeholder="请输入实验室地址"
              v-model:value="form.remark"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="实验室照片">
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="customRequest"
              :before-upload="beforeUpload"
            >
              <img
                v-if="form.picture"
                :src="form.picture"
                alt="avatar"
                style="width: 100px; heidht: 100px"
              />
              <div v-else>
                <a-button>
                  <UploadOutlined></UploadOutlined>
                  点击上传实验室照片
                </a-button>
              </div>
            </a-upload>
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "实验室名称",
    dataIndex: "name",
  },
  {
    title: "实验室编码",
    dataIndex: "code",
  },
  {
    title: "实验室管理员",
    dataIndex: "administintor",
  },
  {
    title: "实验室位置",
    dataIndex: "remark",
  },
  {
    title: "联系方式",
    dataIndex: "phone",
  },
  {
    title: "设备仪器数量",
    dataIndex: "quantity",
  },
  {
    title: "照片",
    dataIndex: "picture",
    slots: { customRender: "picture" },
  },
];
const rules = {
  name: [{ required: true, message: "该为必填项", trigger: "blur" }],
  remark: [{ required: true, message: "该为必填项", trigger: "blur" }],
  phone: [
    {
      pattern:
        /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
      message: "手机号不合法",
      trigger: "blur",
    },
    { required: true, message: "该为必填项", trigger: "blur" },
  ],
};
import { UserList } from "@/server/http/api/team";
import {
  LaboratoryList,
  addLaboratory,
  getLaboratory,
  delLaboratory,
  editLaboratory,
} from "@/server/http/api/Device";
import { message } from "ant-design-vue";
import { uploadFile, delFile } from "@/server/http/api/File";
import { UploadOutlined } from "@ant-design/icons-vue";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules: rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      file: null,
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        orders: [],
        name: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      //用户列表
      selUserList: [],
      //用来存储修改的临时文件路径
      updateUrl: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
    this.getUserList();
  },
  methods: {
    delFileMethod(e) {
      delFile({ fileUrl: e }).then((res) => {});
    },
    //获取用户
    getUserList() {
      UserList().then((res) => {
        var data = res.data.data;
        this.selUserList = data;
      });
    },
    //实验室照片上传
    customRequest(info) {
      let flag = false;
      const formData = new FormData();
      formData.append("file", info.file);
      if (this.form.picture != null && this.updateUrl != this.form.picture) {
        this.delFileMethod(this.form.picture);
      }
      uploadFile(formData).then((res) => {
        this.form.picture = res.data.data.fileUrl;
      });
    },
    //实验室照片传前
    beforeUpload(file) {
      const isJpgOrPng =
        file.type === "image/jpeg" || file.type === "image/png";
      if (!isJpgOrPng) {
        message.warning("只能上传图片!");
      }
      const isLt5M = file.size / 1024 / 1024 < 5;

      if (!isLt5M) {
        message.warning("图片大小不能超过5M!");
      }
      return isJpgOrPng && isLt5M;
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取部门列表
    getList() {
      LaboratoryList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    handleOk(e) {
      var myreg =
        /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/;
      if (
        !myreg.test(this.form.phone) ||
        !this.form.name ||
        !this.form.remark
      ) {
        message.warning("缺少必填参数!");
         return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      if (this.form.picture != null && this.updateUrl != this.form.picture) {
        this.delFileMethod(this.form.picture);
      }
      this.updateUrl = null;
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加实验室";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getLaboratory(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改实验室信息";
        this.updateUrl = response.data.data.picture;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        if (this.form.picture != this.updateUrl) {
          this.delFileMethod(this.updateUrl);
        }
        editLaboratory(this.form)
          .then((response) => {
            this.updateUrl = null;
            this.open = false;
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addLaboratory(this.form)
          .then((response) => {
            this.open = false;
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delLaboratory(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
